  1634→{
  1635→	struct acpi_video_device *video_device = data;
  1636→	struct acpi_device *device = NULL;
  1637→	struct acpi_video_bus *bus;
  1638→	struct input_dev *input;
  1639→	int keycode = 0;
  1640→
  1641→	if (!video_device)
