  1643→
  1644→	device = video_device->dev;
  1645→	bus = video_device->video;
  1646→	input = bus->input;
  1647→
  1648→	if (hw_changes_brightness > 0) {
  1649→		if (video_device->backlight)
  1650→			backlight_force_update(video_device->backlight,
